/**
 * M1 codes identifying the NAR Code of Ethics (COE) training cycle during which a
 * member completed their Fair Housing training requirement. Each numbered cycle
 * corresponds to a three-year compliance period. `"NEW"` indicates a new member
 * who has not yet been assigned to a cycle.
 * - `"6"` through `"11"` — Specific three-year COE compliance cycles
 * - `"NEW"` — New member; cycle not yet assigned
 */
export type COEFairHousingCycleCode = "6" | "7" | "8" | "9" | "10" | "11" | "NEW";